import{form,titulo,conteudo,adicionarEventoLoad,adicionarEventoSubmit,converterNum,limparVal,validarID,validarCampoObrigatorio,enviarDados,redirecionar,}from "./utils.min.js";let id=null;adicionarEventoLoad(()=>{const queryString=window.location.search;const paramsURL=new URLSearchParams(queryString);id=paramsURL.get("id");titulo.value=paramsURL.get("titulo");conteudo.value=paramsURL.get("conteudo")});adicionarEventoSubmit(form,async(e)=>{e.preventDefault();const valID=converterNum(id);const valTitulo=limparVal(titulo.value);const valConteudo=limparVal(conteudo.value);if(!validarID(valID)){redirecionar("Erro: O ID é obrigatório e deve ser um número inteiro maior ou igual a 1.","consultar_notas.html");return}
if(!validarCampoObrigatorio(titulo,valTitulo,80)){redirecionar("Erro: O título é obrigatório e deve conter até 80 caracteres.","consultar_notas.html");return}
if(!validarCampoObrigatorio(conteudo,valConteudo,200)){redirecionar("Erro: O conteúdo é obrigatório e deve conter até 200 caracteres.","consultar_notas.html");return}
const params={acao:"editar_nota",id:id,titulo:valTitulo,conteudo:valConteudo,};const url="editar_nota.php";const metodo="POST";const{dados,msg}=await enviarDados(params,url,metodo);const{acessoNegado}=dados;if(acessoNegado){redirecionar(msg,"login.html");return}
redirecionar(msg,"consultar_notas.html")})